"""Checks that checked-in generated files use the canonical header."""

from __future__ import annotations

import sys
from pathlib import Path

import bootstrap

REPO_ROOT = bootstrap.ensure_runtime_py_on_path(Path(__file__))

from loom.gen.generated_file import GENERATED_FILE_MARKER  # noqa: E402

PRESERVE_BELOW_TAG = "### BAZEL_TO_CMAKE_PRESERVES_ALL_CONTENT_BELOW_THIS_LINE ###"

GENERATED_SOURCE_GLOBS = (
    "loom/py/loom/dialect/*/builders.py",
    "loom/src/loom/editor/textmate/*.tmLanguage.json",
    "loom/src/loom/ops/*/builders.c",
    "loom/src/loom/ops/*/ops.h",
    "loom/src/loom/ops/*/tables.c",
    "loom/src/loom/ops/op_registry.c",
    "loom/src/loom/ops/op_registry.h",
    "loom/src/loom/ops/type_registry.c",
    "loom/src/loom/ops/type_registry.h",
    "loom/src/loom/target/arch/x86/packed_dot_contract_data.c",
    "loom/src/loom/target/arch/x86/packed_dot_contract_data.h",
)

LEGACY_HEADER_FRAGMENTS = (
    "GENERATED by ",
    "Auto-generated by ",
    "Autogenerated by ",
)


def _top_of_file(path: Path, *, line_count: int = 16) -> str:
    lines = path.read_text(encoding="utf-8").splitlines()
    return "\n".join(lines[:line_count])


def _expected_generated_paths() -> list[Path]:
    paths: set[Path] = set()
    for pattern in GENERATED_SOURCE_GLOBS:
        paths.update(REPO_ROOT.glob(pattern))
    for root in (
        REPO_ROOT / "compiler",
        REPO_ROOT / "runtime",
        REPO_ROOT / "samples",
        REPO_ROOT / "tests",
        REPO_ROOT / "tools",
    ):
        for path in root.rglob("CMakeLists.txt"):
            header = _top_of_file(path)
            text = path.read_text(encoding="utf-8")
            has_generated_header = GENERATED_FILE_MARKER in header
            has_legacy_header = any(fragment in header for fragment in LEGACY_HEADER_FRAGMENTS)
            if PRESERVE_BELOW_TAG in text and (has_generated_header or has_legacy_header):
                paths.add(path)
    return sorted(paths)


def main() -> int:
    failures: list[str] = []
    for path in _expected_generated_paths():
        relative_path = path.relative_to(REPO_ROOT)
        header = _top_of_file(path)
        if GENERATED_FILE_MARKER not in header:
            failures.append(f"{relative_path}: missing {GENERATED_FILE_MARKER!r}")
        failures.extend(f"{relative_path}: legacy generated header fragment {fragment!r}" for fragment in LEGACY_HEADER_FRAGMENTS if fragment in header)
    if failures:
        print("generated header check failed:", file=sys.stderr)
        for failure in failures:
            print(f"  {failure}", file=sys.stderr)
        return 1
    print(f"checked {len(_expected_generated_paths())} generated files")
    return 0


if __name__ == "__main__":
    sys.exit(main())
